// OpenClaw Sentinel Health Alert
// Polls /internal/sentinel, builds a deterministic fingerprint from
// the check results, and decides whether to alert, suppress, or
// send a recovery message.
//
// Runtime: uses Node.js http module (n8n sandbox compatible).

// === CONFIGURATION — edit these after importing ===
const API_BASE = 'CONFIGURE_ME'; // e.g. 'http://localhost:8000'
const API_KEY = 'CONFIGURE_ME';  // OPENCLAW_API_KEY value, or '' for dev
const COOLDOWN_HOURS = 6;        // Suppress repeat alerts for unchanged state

// --- Helpers ---
const http = require('http');

function apiFetch(path) {
  return new Promise((resolve, reject) => {
    const headers = { 'Content-Type': 'application/json' };
    if (API_KEY && API_KEY !== 'CONFIGURE_ME') {
      headers['X-API-Key'] = API_KEY;
    }
    http.get(`${API_BASE}${path}`, { headers }, (res) => {
      let body = '';
      res.on('data', chunk => body += chunk);
      res.on('end', () => {
        if (res.statusCode >= 400) {
          reject(new Error(`API ${path} returned ${res.statusCode}`));
          return;
        }
        try { resolve(JSON.parse(body)); }
        catch (e) { reject(new Error(`Invalid JSON from ${path}`)); }
      });
    }).on('error', reject);
  });
}

function buildFingerprint(data) {
  // Deterministic fingerprint: status + sorted list of check names
  // Examples:
  //   ok|
  //   watch|stale_claims
  //   alert|event_spine_silent,source_needs_attention
  if (!data.findings || data.findings.length === 0) {
    return `${data.status}|`;
  }
  const checks = data.findings.map(f => f.check).sort().join(',');
  return `${data.status}|${checks}`;
}

function timeSince(isoStr) {
  if (!isoStr) return null;
  const ms = Date.now() - new Date(isoStr).getTime();
  const hours = Math.floor(ms / 3600000);
  if (hours < 1) return 'hace <1h';
  if (hours < 24) return `hace ${hours}h`;
  const days = Math.floor(hours / 24);
  return `hace ${days}d`;
}

const severityEmoji = { high: '\u{1F6A8}', medium: '\u26A0\uFE0F', low: '\u{1F7E1}' };
const statusEmoji = { ok: '\u2705', watch: '\u26A0\uFE0F', alert: '\u{1F6A8}' };

// --- Fetch sentinel ---
const data = await apiFetch('/internal/sentinel');
const fingerprint = buildFingerprint(data);

// --- State management ---
const staticData = $getWorkflowStaticData('global');
const lastFingerprint = staticData.lastFingerprint || null;
const lastAlertedAt = staticData.lastAlertedAt || null;
const lastOverallStatus = staticData.lastOverallStatus || null;

// --- Decision logic ---
// 1. Fingerprint changed → alert immediately
// 2. Fingerprint unchanged + non-ok + cooldown expired → repeat alert
// 3. Fingerprint returned to ok| after non-ok → recovery message
// 4. Otherwise → suppress

const isOk = data.status === 'ok';
const wasOk = lastFingerprint === null || lastFingerprint === 'ok|';
const fingerprintChanged = fingerprint !== lastFingerprint;

let shouldSend = false;
let isRecovery = false;

if (isOk && !wasOk) {
  // Recovery: was non-ok, now ok
  shouldSend = true;
  isRecovery = true;
} else if (isOk) {
  // Still ok, nothing to do
  shouldSend = false;
} else if (fingerprintChanged) {
  // New or changed problem → alert immediately
  shouldSend = true;
} else if (lastAlertedAt) {
  // Same fingerprint, check cooldown
  const hoursSince = (Date.now() - new Date(lastAlertedAt).getTime()) / 3600000;
  if (hoursSince >= COOLDOWN_HOURS) {
    shouldSend = true;
  }
} else {
  // No previous alert timestamp but non-ok → alert
  shouldSend = true;
}

if (!shouldSend) {
  // Update lastOverallStatus even when suppressed (tracks transitions)
  staticData.lastOverallStatus = data.status;
  return [];
}

// --- Format message ---
const now = new Date();
const dayNames = ['Dom', 'Lun', 'Mar', 'Mi\u00e9', 'Jue', 'Vie', 'S\u00e1b'];
const dateStr = `${dayNames[now.getDay()]} ${now.getDate()}/${(now.getMonth()+1).toString().padStart(2,'0')} ${now.getHours().toString().padStart(2,'0')}:${now.getMinutes().toString().padStart(2,'0')}`;

const lines = [];

if (isRecovery) {
  lines.push(`\u2705 Sentinel OK \u2014 ${dateStr}`);
  lines.push('');
  lines.push('Sistema recuperado. Todas las comprobaciones pasaron.');
  if (lastOverallStatus) {
    lines.push(`Estado anterior: ${lastOverallStatus}`);
  }
} else {
  const emoji = statusEmoji[data.status] || '\u26A0\uFE0F';
  lines.push(`${emoji} Sentinel ${data.status.toUpperCase()} \u2014 ${dateStr}`);
  lines.push('');
  lines.push(`${data.total_findings} problema${data.total_findings > 1 ? 's' : ''} detectado${data.total_findings > 1 ? 's' : ''}`);
  lines.push('');

  // Group findings by severity (high first)
  const bySeverity = { high: [], medium: [], low: [] };
  for (const f of data.findings) {
    const bucket = bySeverity[f.severity];
    if (bucket) bucket.push(f);
    else bySeverity.low.push(f);
  }

  for (const sev of ['high', 'medium', 'low']) {
    const items = bySeverity[sev];
    if (items.length === 0) continue;
    for (const f of items) {
      const e = severityEmoji[sev] || '\u{1F7E1}';
      lines.push(`${e} [${f.check}] ${f.message}`);
      lines.push(`  \u2192 ${f.recommended_action}`);
    }
  }

  // Cooldown note if this is a repeat
  if (!fingerprintChanged && lastAlertedAt) {
    const ago = timeSince(lastAlertedAt);
    lines.push('');
    lines.push(`(Repetido \u2014 mismo estado desde ${ago})`);
  }
}

lines.push('');
lines.push(`Fingerprint: ${fingerprint}`);

return [{ json: { text: lines.join('\n'), fingerprint: fingerprint, isRecovery: isRecovery } }];

// Update state — only runs after successful Telegram send
const staticData = $getWorkflowStaticData('global');
const item = $input.all()[0]?.json || {};

staticData.lastFingerprint = item.fingerprint || null;
staticData.lastAlertedAt = new Date().toISOString();
// Track overall status for recovery messages
const parts = (item.fingerprint || '').split('|');
staticData.lastOverallStatus = parts[0] || 'ok';

// On recovery, clear alert timestamp so next issue alerts immediately
if (item.isRecovery) {
  staticData.lastAlertedAt = null;
}

return [{ json: { updated: true, fingerprint: item.fingerprint } }];
